  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `sales_order_id` bigint(20) unsigned NOT NULL,
  `warehouse_id` bigint(20) unsigned NOT NULL,
  `sku` varchar(255) DEFAULT NULL,
  `return_quantity` int(11) DEFAULT NULL,
  `return_reason` varchar(255) DEFAULT NULL,
  `return_description` varchar(255) DEFAULT NULL,
  `return_status` enum('pending','accept','on_the_way','returned','completed') DEFAULT 'pending' COMMENT 'pending, accept, on the way, returned, completed',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `customer_returns_sales_order_id_foreign` (`sales_order_id`),
  KEY `customer_returns_warehouse_id_foreign` (`warehouse_id`),
  CONSTRAINT `customer_returns_sales_order_id_foreign` FOREIGN KEY (`sales_order_id`) REFERENCES `sales_orders` (`id`) ON DELETE CASCADE,
  CONSTRAINT `customer_returns_warehouse_id_foreign` FOREIGN KEY (`warehouse_id`) REFERENCES `warehouses` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
