CREATE TABLE `temp_orders` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `customer_name` varchar(255) DEFAULT NULL,
  `po_number` varchar(255) DEFAULT NULL,
  `sku` varchar(255) DEFAULT NULL,
  `facility_name` varchar(255) DEFAULT NULL,
  `facility_location` text DEFAULT NULL,
  `po_date` varchar(255) DEFAULT NULL,
  `po_expiry_date` varchar(255) DEFAULT NULL,
  `hsn` varchar(255) DEFAULT NULL,
  `portal_code` varchar(255) DEFAULT NULL,
  `gst` varchar(255) DEFAULT NULL,
  `item_code` varchar(255) DEFAULT NULL,
  `description` varchar(255) DEFAULT NULL,
  `basic_rate` varchar(255) DEFAULT '0',
  `product_basic_rate` varchar(255) DEFAULT '0',
  `rate_confirmation` varchar(255) DEFAULT NULL,
  `net_landing_rate` varchar(255) DEFAULT '0',
  `product_net_landing_rate` varchar(255) DEFAULT '0',
  `net_landing_rate_confirmation` varchar(255) DEFAULT NULL,
  `mrp` varchar(255) DEFAULT '0',
  `product_mrp` double NOT NULL DEFAULT 0,
  `mrp_confirmation` varchar(255) DEFAULT NULL,
  `po_qty` varchar(255) DEFAULT NULL,
  `available_quantity` varchar(255) DEFAULT NULL,
  `available_quantity_track` decimal(15,2) DEFAULT 0.00,
  `unavailable_quantity` varchar(255) DEFAULT NULL,
  `unavailable_quantity_track` decimal(15,2) DEFAULT 0.00,
  `block` varchar(255) DEFAULT NULL,
  `case_pack_quantity` varchar(255) DEFAULT NULL,
  `purchase_order_quantity` varchar(255) DEFAULT NULL,
  `vendor_code` varchar(255) DEFAULT NULL,
  `vendor_pi_id` varchar(255) DEFAULT NULL,
  `vendor_pi_fulfillment_quantity` varchar(255) DEFAULT '0',
  `vendor_pi_received_quantity` varchar(255) DEFAULT '0',
  `customer_status` varchar(255) DEFAULT NULL,
  `vendor_status` varchar(255) DEFAULT NULL,
  `product_status` varchar(255) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=5202 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
